import api from './api';

export const getQuestionaryData = async () => {
  const response = await api.get('/questionary');
  console.log(`response = get('/questionary'): `, response.data);
  return response.data;
};

export const getQuestionaryById = async (id) => {
  const response = await api.get(`/questionary/${id}`);
  return response.data;
};

export const getQuestionaryByLevelId = async (levelId) => {
  const response = await api.get(`/questionary/code/${levelId}`);
  return response.data;
};

export const createQuestionaryData = async () => {
  const response = await api.get('/questionary');
  return response.data;
};

export const updateQuestionaryData = async (id) => {
  const response = await api.get(`/questionary/${id}`);
  return response.data;
};

export const deleteQuestionaryData = async (id) => {
  const response = await api.get(`/questionary/${id}`);
  return response.data;
};

