import React, { useState, useEffect } from 'react';
import { useQuery } from 'react-query';
import { Card, Row, Col, Form, Button, Badge } from 'react-bootstrap';
import { MapContainer, TileLayer, Popup, CircleMarker } from 'react-leaflet';
import { getMapData } from '../../services/dashboardService';
import { getDistrict, getSubdistrict } from '../../services/commonService';
import 'leaflet/dist/leaflet.css';

// Fix for default markers in react-leaflet
import L from 'leaflet';
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require('leaflet/dist/images/marker-icon-2x.png'),
  iconUrl: require('leaflet/dist/images/marker-icon.png'),
  shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
});

const MapView = () => {
  const [selectedDistrict, setSelectedDistrict] = useState('');
  const [mapCenter, setMapCenter] = useState([4.1652, 126.7780]); // Talaud coordinates
  const [zoom, setZoom] = useState(9);
  const [districts, setDistricts] = useState([]);
  const [subdistricts, setSubdistricts] = useState([]);

      // Effect pertama: ambil data districts saat load awal
    useEffect(() => {
      const fetchDistricts = async () => {
        try {
          const data = await getDistrict();
          setDistricts(data.data);
        } catch (error) {
          console.error("Gagal ambil district:", error);
        }
      };
      fetchDistricts(); 
    }, []);
  
      // Effect pertama: ambil data districts saat load awal
    useEffect(() => {
      const fetchSubDistricts = async () => {
        try {
          const data = await getSubdistrict();
          setSubdistricts(data.data);
        } catch (error) {
          console.error("Gagal ambil sub district:", error);
        }
      };
      fetchSubDistricts(); 
    }, []);
  
  const { data: mapData, isLoading, error } = useQuery(
    ['mapData', selectedDistrict],
    () => getMapData(selectedDistrict),
    { keepPreviousData: true }
  );

  const getMarkerColor = (score) => {
    if (score >= 80) return '#28a745'; // Green for good
    if (score >= 60) return '#ffc107'; // Yellow for moderate
    return '#dc3545'; // Red for poor
  };

  const getScoreLabel = (score) => {
    if (score >= 80) return 'Layak Huni';
    if (score >= 60) return 'Kurang Layak Huni';
    return 'Tidak Layak Huni';
  };

  const handleDistrictChange = (e) => {
    setSelectedDistrict(e.target.value);
  };

  const handleMarkerClick = (housing) => {
    // You can add custom logic here for marker clicks
    console.log('Marker clicked:', housing);
  };

  if (isLoading) return <div className="loading-spinner">Loading peta...</div>;
  if (error) return <div className="error-message">Error: {error.message}</div>;

  return (
    <div className="container-fluid">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2>Peta Rumah</h2>
        <div className="d-flex gap-2">
          <Form.Select
            value={selectedDistrict}
            onChange={handleDistrictChange}
            style={{ width: '200px' }}
          >
            <option value="">Semua Kecamatan</option>
                  {districts.map((d) => (
                    <option key={d.id} value={d.id}>
                      {d.name}
                    </option>
                  ))}
          </Form.Select>
        </div>
      </div>

      <Row>
        <Col md={9}>
          <Card>
            <Card.Body style={{ padding: 0 }}>
              <div style={{ height: '600px', width: '100%' }}>
                <MapContainer
                  center={mapCenter}
                  zoom={zoom}
                  style={{ height: '100%', width: '100%', zIndex: 0 }}
                >
                  <TileLayer
                    url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                    attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                  />
                  
                  {mapData?.map((housing) => {
                    if (!housing.latitude || !housing.longitude) return null;
                    
                    const score = housing.assessment_score || 0;
                    const color = getMarkerColor(score);
                    
                    return (
                      <CircleMarker
                        key={housing.id}
                        center={[parseFloat(housing.latitude), parseFloat(housing.longitude)]}
                        radius={8}
                        pathOptions={{ 
                          color: color, 
                          fillColor: color, 
                          fillOpacity: 0.7 
                        }}
                        eventHandlers={{
                          click: () => handleMarkerClick(housing)
                        }}
                      >
                        <Popup>
                          <div style={{ minWidth: '200px' }}>
                            <h6>BR-{housing.id}</h6>
                            <p><strong>Alamat:</strong> {housing.address}</p>
                            <p><strong>Kecamatan:</strong> {housing.district_name}</p>
                            <p><strong>Desa/Kelurahan:</strong> {housing.sub_district_name}</p>
                            <p><strong>Jenis Bangunan:</strong> {housing.building_type}</p>
                            <p><strong>Luas Bangunan:</strong> {housing.house_area_m2} m²</p>
                            {score > 0 && (
                              <div>
                                <p><strong>Skor Kelayakan:</strong></p>
                                <Badge bg={score >= 80 ? 'success' : score >= 60 ? 'warning' : 'danger'}>
                                  {score.toFixed(1)} - {getScoreLabel(score)}
                                </Badge>
                              </div>
                            )}
                            <div className="mt-2">
                              <Button 
                                size="sm" 
                                variant="outline-primary"
                                onClick={() => window.open(`/housing/${housing.id}`, '_blank')}
                              >
                                Lihat Detail
                              </Button>
                            </div>
                          </div>
                        </Popup>
                      </CircleMarker>
                    );
                  })}
                </MapContainer>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={3}>
          <Card>
            <Card.Header>
              <h5>Legenda</h5>
            </Card.Header>
            <Card.Body>
              <div className="mb-3">
                <div className="d-flex align-items-center mb-2">
                  <div 
                    style={{ 
                      width: '16px', 
                      height: '16px', 
                      backgroundColor: '#28a745', 
                      borderRadius: '50%',
                      marginRight: '8px'
                    }}
                  ></div>
                  <span>Layak Huni (≥80)</span>
                </div>
                <div className="d-flex align-items-center mb-2">
                  <div 
                    style={{ 
                      width: '16px', 
                      height: '16px', 
                      backgroundColor: '#ffc107', 
                      borderRadius: '50%',
                      marginRight: '8px'
                    }}
                  ></div>
                  <span>Kurang Layak Huni (60-79)</span>
                </div>
                <div className="d-flex align-items-center mb-2">
                  <div 
                    style={{ 
                      width: '16px', 
                      height: '16px', 
                      backgroundColor: '#dc3545', 
                      borderRadius: '50%',
                      marginRight: '8px'
                    }}
                  ></div>
                  <span>Tidak Layak Huni (&lt;60)</span>
                </div>
              </div>

              <div className="mt-4">
                <h6>Statistik</h6>
                <div className="mb-2">
                  <small className="text-muted">Total Data:</small>
                  <br />
                  <strong>{mapData?.length || 0} rumah</strong>
                </div>
                {mapData && mapData.length > 0 && (
                  <>
                    <div className="mb-2">
                      <small className="text-muted">Dengan Koordinat:</small>
                      <br />
                      <strong>
                        {mapData.filter(h => h.latitude && h.longitude).length} rumah
                      </strong>
                    </div>
                    <div className="mb-2">
                      <small className="text-muted">Dengan Penilaian:</small>
                      <br />
                      <strong>
                        {mapData.filter(h => h.assessment_score).length} rumah
                      </strong>
                    </div>
                  </>
                )}
              </div>

              <div className="mt-4">
                <h6>Kontrol Peta</h6>
                <div className="d-grid gap-2">
                  <Button 
                    size="sm" 
                    variant="outline-secondary"
                    onClick={() => {
                      setMapCenter([3.5952, 126.9780]);
                      setZoom(11);
                    }}
                  >
                    Reset View
                  </Button>
                  <Button 
                    size="sm" 
                    variant="outline-info"
                    onClick={() => {
                      if (mapData && mapData.length > 0) {
                        const coords = mapData
                          .filter(h => h.latitude && h.longitude)
                          .map(h => [parseFloat(h.latitude), parseFloat(h.longitude)]);
                        
                        if (coords.length > 0) {
                          // You would need to access the map instance to fit bounds
                          // This is a simplified version
                        }
                      }
                    }}
                  >
                    Fit All Markers
                  </Button>
                </div>
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </div>
  );
};

export default MapView; 