import api from './api';

export const getDashboardSummary = async () => {
  try {
    const token = localStorage.getItem('token');
    // console.log(token);
    const response = await api.get('/dashboard/summary', {
      headers: {
        Authorization: `Bearer ${token}`
      }}
    );
    return response.data;
  } catch (error) {
    throw error;
  }
};

