// file: ScoringForm.js
import React, { useEffect, useState } from 'react';
import { Form, Button, Card, Collapse } from 'react-bootstrap';
import { updateScoringData } from '../../services/scoringService';
import { getQuestionaryData } from '../../services/questionaryService';

const ScoringForm = ({ housingId, onSuccess }) => {
  const [questionary, setQuestionary] = useState([]);
  const [answers, setAnswers] = useState({});
  const [open, setOpen] = useState({});
  const [showScores, setShowScores] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await getQuestionaryData();
        setQuestionary(res.data);

        const initialOpen = {};
        res.data
          .filter(q => q.has_child === 1 && q.child_format === 0)
          .forEach(r => { initialOpen[r.id] = true; });
        setOpen(initialOpen);
      } catch (err) {
        console.error(err);
      }
    };
    fetchData();
  }, []);

  const handleChange = (qid, value, multiple = false) => {
    setAnswers(prev => {
      if (multiple) {
        const existing = prev[qid] ? prev[qid].split(',') : [];
        let updated;
        if (existing.includes(value)) {
          updated = existing.filter(v => v !== value);
        } else {
          updated = [...existing, value];
        }
        return { ...prev, [qid]: updated.join(',') };
      }
      return { ...prev, [qid]: value };
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const payload = Object.entries(answers).map(([qid, val]) => ({
        housing_id: housingId,
        questionary_id: qid,
        value: val,
        weight: 0
      }));
      await updateScoringData(payload);
      onSuccess();
    } catch (err) {
      console.error("Gagal simpan scoring:", err);
    }
  };

  const getChildren = (node) => {
    const parts = [node["1"], node["2"], node["3"], node["4"], node["5"], node["6"], node["7"]];
    const depth = parts.filter(x => x !== 0).length;

    return questionary.filter(q => {
      const qParts = [q["1"], q["2"], q["3"], q["4"], q["5"], q["6"], q["7"]];
      const qDepth = qParts.filter(x => x !== 0).length;
      if (qDepth !== depth + 1) return false;
      for (let i = 0; i < depth; i++) {
        if (parts[i] !== qParts[i]) return false;
      }
      return true;
    });
  };

  const calculateScore = (node) => {
    const children = getChildren(node);
    const weight = node.weight ? Number(node.weight) : 1;

    if (!children.length) {
      const parentPath = node.path_index.split('.').slice(0, -1).join('.');
      const val = answers[parentPath];
      if (val && String(val) === String(node.id)) {
        return Number(node.weight || node.value || 0);
      }
      return 0;
    }

    const totalChild = children.reduce((acc, child) => acc + calculateScore(child), 0);
    return totalChild * weight;
  };

  const renderNode = (node) => {
    if (node.has_child === 1 && node.child_format === 0) {
      // const isRoot = node["2"] === 0;
      return (
        <Card key={node.id} className="mb-2">
          <Card.Header
            onClick={() => setOpen(prev => ({ ...prev, [node.id]: !prev[node.id] }))}
            aria-controls={`collapse-${node.id}`}
            aria-expanded={open[node.id]}
            style={{ cursor: 'pointer' }}
            className="d-flex justify-content-between align-items-center gap-2"
          >
            <span className='align-items-center gap-2'>{node.path_index} - {node.description}

              {showScores && <span className='align-items-center me-auto'>&nbsp; | NILAI: {calculateScore(node)}</span>}
              {/* {isRoot && (
                <>
                  <Button
                    size="sm"
                    variant="outline-secondary"
                    onClick={(e) => {
                      e.stopPropagation();
                      setShowScores(prev => !prev);
                    }}
                  >
                    {showScores ? "Hide Nilai" : "Show Nilai"}
                  </Button>
                  <Button
                    size="sm"
                    variant="outline-primary"
                    onClick={(e) => {
                      e.stopPropagation();
                      const newState = {};
                      if (Object.values(open).some(v => v)) {
                        questionary
                          .filter(q => q.has_child === 1 && q.child_format === 0)
                          .forEach(q => { newState[q.id] = false; });
                      } else {
                        questionary
                          .filter(q => q.has_child === 1 && q.child_format === 0)
                          .forEach(q => { newState[q.id] = true; });
                      }
                      setOpen(prev => ({ ...prev, ...newState }));
                    }}
                  >
                    {Object.values(open).some(v => v) ? "Collapse All" : "Expand All"}
                  </Button>
                </>
              )} */}
            </span>
            <span>
              {open[node.id]
                ? <span className='ms-auto'> <i className="fas fa-chevron-up"></i></span>
                : <i className="fas fa-chevron-down"></i>}
            </span>
          </Card.Header>
          <Collapse in={open[node.id]} mountOnEnter unmountOnExit={false}>
            <div id={`collapse-${node.id}`} className="ms-3">
              {getChildren(node).map(child => renderNode(child))}
            </div>
          </Collapse>
        </Card>
      );
    }

    if (node.has_child === 1 && node.child_format === 1) {
      const children = getChildren(node);
      return (
        <Form.Group key={node.id} className="ms-3 mb-3">
          <strong>
            {node.path_index} - {node.description}
            {showScores && <> | NILAI: {calculateScore(node)}</>}
          </strong>
          <div className="ms-3">
            {children.map(child => (
              <Form.Check
                key={child.id}
                id={`check-${child.path_index}`}
                type="radio"
                name={`group-${node.path_index}`}
                label={`${child.path_index} - ${child.description}`}
                value={child.id}
                checked={answers[node.path_index] === String(child.id)}
                onChange={(e) => handleChange(node.path_index, e.target.value)}
              />
            ))}
          </div>
        </Form.Group>
      );
    }

    if (node.has_child === 1 && node.child_format === 2) {
      const children = getChildren(node);
      const selected = answers[node.path_index] ? answers[node.path_index].split(',') : [];
      return (
        <Form.Group key={node.id} className="ms-3 mb-3">
          <strong>
            {node.path_index} - {node.description}
            {showScores && <> | NILAI: {calculateScore(node)}</>}
          </strong>
          <div className="ms-3">
            {children.map(child => (
              <Form.Check
                key={child.id}
                id={`check-${child.path_index}`}
                type="checkbox"
                name={`group-${node.path_index}`}
                label={`${child.path_index} - ${child.description}`}
                value={child.id}
                checked={selected.includes(String(child.id))}
                onChange={(e) => handleChange(node.path_index, e.target.value, true)}
              />
            ))}
          </div>
        </Form.Group>
      );
    }

    if (node.has_child === 0) {
      const parentPath = node.path_index.split('.').slice(0, -1).join('.');
      return (
        <Form.Group key={node.id} className="ms-4 mb-2">
          <Form.Check
            id={`check-${node.path_index}`}
            type="radio"
            name={`group-${parentPath}`}
            label={`${node.path_index} - ${node.description}`}
            value={node.id}
            checked={answers[parentPath] === String(node.id)}
            onChange={(e) => handleChange(parentPath, e.target.value)}
          />
        </Form.Group>
      );
    }

    return null;
  };

  const roots = questionary.filter(q => q["2"] === 0);

  return (
    <Form onSubmit={handleSubmit}>
      {/* Global Control Bar */}
      <div className="d-flex justify-content-end gap-2 mb-3">
        <Button
          size="sm"
          variant="outline-secondary"
          onClick={() => setShowScores(prev => !prev)}
        >
          {showScores ? "Sembunyikan Nilai" : "Tampilkan Nilai"}
        </Button>

        <Button
          size="sm"
          variant="outline-primary"
          onClick={() => {
            const newState = {};
            if (Object.values(open).some(v => v)) {
              questionary
                .filter(q => q.has_child === 1 && q.child_format === 0)
                .forEach(q => { newState[q.id] = false; });
            } else {
              questionary
                .filter(q => q.has_child === 1 && q.child_format === 0)
                .forEach(q => { newState[q.id] = true; });
            }
            setOpen(prev => ({ ...prev, ...newState }));
          }}
        >
          {Object.values(open).some(v => v) ? "Tutup Kuesioneri" : "Buka Kuesioneri"}
        </Button>
      </div>

      {roots.map(r => renderNode(r))}
      <Button type="submit" className="mt-3">Simpan</Button>
    </Form>
  );
};

export default ScoringForm;
