import React, { useState, useEffect } from 'react';
import { useQuery } from 'react-query';
import { Card, Table, Button, Form, InputGroup, Modal } from 'react-bootstrap';
// import { toast } from 'react-toastify'; // reserved for deleting procedure
import { getScoringSummary} from '../../services/scoringService';
// import { useAuth } from '../../contexts/AuthContext';
import ScoringForm from './ScoringForm';
import { getDistrict, getSubdistrictByDistrict } from '../../services/commonService';

const ScoringData = () => {
  // const { user } = useAuth();
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [showForm, setShowForm] = useState(false);
  const [selectedScoring, setSelectedScoring] = useState(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  // const [deleteId, setDeleteId] = useState(null);
  // State untuk district & subdistrict
  const [districts, setDistricts] = useState([]);
  const [selectedDistrict, setSelectedDistrict] = useState("");
  const [subdistricts, setSubdistricts] = useState([]);
  const [selectedSubdistrict, setSelectedSubdistrict] = useState("");

  const { data: scoringData, isLoading, error, refetch } = useQuery(
    ['scoringData', currentPage, searchTerm, selectedDistrict, selectedSubdistrict],
    () => getScoringSummary({ 
      page: currentPage, 
      search: searchTerm, 
      district: selectedDistrict, 
      subdistrict: selectedSubdistrict }),
    { keepPreviousData: true }
  );

  // Effect pertama: ambil data districts saat load awal
  useEffect(() => {
    const fetchDistricts = async () => {
      try {
        const data = await getDistrict();
        setDistricts(data.data);
      } catch (error) {
        console.error("Gagal ambil district:", error);
      }
    };
    fetchDistricts(); 
  }, []);
  
  // Effect kedua: ambil subdistrict tiap kali district berubah
  useEffect(() => {
    const fetchSubdistricts = async () => {
      if (selectedDistrict) {
        try {
          const data = await getSubdistrictByDistrict(selectedDistrict);
          setSubdistricts(data.data);

        } catch (error) {
          console.error("Gagal ambil subdistrict:", error);
        }
      } else {
        setSubdistricts([]);
      }
    };
    fetchSubdistricts();
  }, [selectedDistrict]);
  
  const handleEdit = (scoring) => {
    setSelectedScoring(scoring);
    setShowForm(true);
  };

  // const handleDelete = (id) => {
  //   setDeleteId(id);
  //   setShowDeleteModal(true);
  // };

  // const confirmDelete = async () => {
  //   try {
  //     await deleteScoringData(deleteId);
  //     toast.success('Data berhasil dihapus');
  //     refetch();
  //     setShowDeleteModal(false);
  //   } catch (error) {
  //     toast.error('Gagal menghapus data');
  //   }
  // };

// Handle pilih district
const handleDistrictChange = async (e) => {
  const districtId = e.target.value;
  setSelectedDistrict(districtId);
  setSelectedSubdistrict(""); // reset subdistrict kalau ganti district

  if (districtId) {
    try {
      const data = await getSubdistrictByDistrict(districtId); // asumsi ada fungsi ini
      setSubdistricts(data.data);
    } catch (error) {
      console.error("Gagal ambil subdistrict:", error);
      setSubdistricts([]);
    }
  } else {
    setSubdistricts([]);
  }
};

// Handle pilih subdistrict
const handleSubdistrictChange = (e) => {
  setSelectedSubdistrict(e.target.value);
};

  const handleFormClose = () => {
    setShowForm(false);
    setSelectedScoring(null);
  };

  const handleFormSuccess = () => {
    refetch();
    handleFormClose();
  };

  if (isLoading) return <div className="loading-spinner">Loading...</div>;
  if (error) return <div className="error-message">Error: {error.message}</div>;

  return (
    <div className="container-fluid">
      <div className="d-flex justify-content-between align-items-center mb-4 w-100">
        <h2>Penilaian</h2>
        {/* {user?.role === 'admin' || user?.role === 'pengguna' ? (
          <Button variant="primary" onClick={() => setShowForm(true)}>
            <i className="fas fa-plus me-2"></i>
            Tambah Data
          </Button>
        ) : null} */}
      </div>

      <Card>
        <Card.Body>
          <div className="row mb-3">
            <div className="col-md-6 d-flex flex-row">
              <div className="col-md-6 d-flex gap-2">
                <Form.Select
                  value={selectedDistrict}
                  onChange={handleDistrictChange}
                  style={{ width: '200px' }}
                >
                  <option value="">Semua Kecamatan</option>
                        {districts.map((d) => (
                          <option key={d.id} value={d.id}>
                            {d.name}
                          </option>
                        ))}
                </Form.Select>
              </div>

              <div className="col-md-6 d-flex gap-2">
                <Form.Select
                  value={selectedSubdistrict}
                  onChange={handleSubdistrictChange}
                  style={{ width: '200px' }}
                  disabled={!selectedDistrict} // disabled jika tidak ada district dipilih
                >
                  <option value="">Semua Desa</option>
                        {subdistricts.map((s) => (
                          <option key={s.id} value={s.id}>
                            {s.name}
                          </option>
                        ))}
                </Form.Select>
              </div>
            </div>
            <div className="col-md-6">
              <InputGroup>
                <InputGroup.Text>
                  <i className="fas fa-search"></i>
                </InputGroup.Text>
                <Form.Control
                  type="text"
                  placeholder="Cari data..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </InputGroup>
            </div>
          </div>

          <Table responsive striped hover>
            <thead>
              <tr>
                <th>No</th>
                <th>Kode Rumah</th>
                <th>Kode Scoring</th>
                <th>Uraian</th>
                <th>Total</th>
                <th>Bobot</th>
                <th>Nilai</th>
                <th>Kategori</th>
                <th>Aksi</th>
              </tr>
            </thead>
            <tbody>
              {scoringData?.data?.map((scoring, index) => (
                <tr key={scoring.id}>
                  <td>{(currentPage - 1) * 10 + index + 1}</td>
                  <td>{scoring.housing_id}</td>
                  <td>{scoring.scoring_code}</td>
                  <td>{scoring.description}</td>
                  <td>{scoring.total}</td>
                  <td>{scoring.weight}</td>
                  <td>{scoring.value}</td>
                  <td>{scoring.note}</td>
                  <td>
                    <div className='btn-group' role='group'>
                    <Button
                      size="sm"
                      variant="info"
                      className="me-3 action-btn"
                      onClick={() => handleEdit(scoring)}
                      >
                      <i className="fas fa-edit"></i>
                    </Button>
                    {/* {(user?.role === 'admin' || user?.role === 'pengguna') && (
                      <Button
                      size="sm"
                      variant="danger"
                      className="me-3 action-btn"
                      onClick={() => handleDelete(scoring.id)}
                      >
                        <i className="fas fa-trash"></i>
                      </Button>
                    )} */}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </Table>

          {/* Pagination */}
          {scoringData?.pagination && (
            <div className="d-flex justify-content-between align-items-center">
              <div>
                Menampilkan {scoringData.pagination.from} - {scoringData.pagination.to} dari {scoringData.pagination.total} data
              </div>
              <div>
                <Button
                  variant="outline-primary"
                  size="sm"
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(currentPage - 1)}
                  className="me-2"
                >
                  Sebelumnya
                </Button>
                <Button
                  variant="outline-primary"
                  size="sm"
                  disabled={currentPage >= scoringData.pagination.totalPages}
                  onClick={() => setCurrentPage(currentPage + 1)}
                >
                  Selanjutnya
                </Button>
              </div>
            </div>
          )}
        </Card.Body>
      </Card>

      {/* Scoring Form Modal */}
      <Modal show={showForm} onHide={handleFormClose} size="lg">
        <Modal.Header closeButton>
          <Modal.Title>
            {selectedScoring ? `Edit Data Penilaian Bangunan ${selectedScoring['housing_id']}` : 'Tambah Data Rumah'} 
          </Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <ScoringForm
            scoring={selectedScoring}
            onSuccess={handleFormSuccess}
            onCancel={handleFormClose}
          />
        </Modal.Body>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal show={showDeleteModal} onHide={() => setShowDeleteModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Konfirmasi Hapus</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          Deleting suspended...
          {/* Apakah Anda yakin ingin menghapus data ini? */}
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>
            Batal
          </Button>
          {/* <Button variant="danger" onClick={confirmDelete}>
            Hapus
          </Button> */}
        </Modal.Footer>
      </Modal>
    </div>
  );
};

export default ScoringData; 