import api from './api';

export const getHousingData = async (params = {}) => {
  const response = await api.get('/housing', { params });
  // BO DEBUG
  console.log('getHousingData Response data: ',response.data);
  // EO DEBUG
  return response.data;
};

export const getHousingDataById = async (id) => {
  const response = await api.get(`/housing/${id}`);
  return response.data;
};

export const createHousingData = async (formData) => {
  console.log('formData:', formData);
  for (let [key, value] of formData.entries()) {
    console.log(`formData ${key}:`, value);
  }
  const response = await api.post('/housing', formData, {
    headers: {
      'Content-Type': 'multipart/form-data',
    },
  });
  return response.data;
};

export const updateHousingData = async (housing_id, formData) => {
  const response = await api.put(`/housing/${housing_id}`, formData, {
    headers: {
      'Content-Type': 'multipart/form-data',
    },
  });
  return response.data;
};

export const deleteHousingData = async (id) => {
  const response = await api.delete(`/housing/${id}`);
  return response.data;
}; 

// Ambil foto berdasarkan nama file
export const getHousingPhoto = async (filename) => {
  const response = await api.get(`/housing/photo/${filename}`, {
    responseType: 'blob',
  });
  return URL.createObjectURL(response.data);
};


