const handlePhotoChange = async (e) => {
  const file = e.target.files?.[0];
  if (!file) {
    setPhotoFile(null);
    setPhotoPreview(null);
    return;
  }

  try {
    // compress to <= 1 MB
    const compressed = await compressImage(file, { maxSizeMB: 1, maxWidth: 1600, maxHeight: 1600 });
    setPhotoFile(compressed);
    // show preview from blob URL (faster than base64)
    const url = URL.createObjectURL(compressed);
    setPhotoPreview(url);
  } catch (err) {
    console.error('Gagal kompres gambar:', err);
    // fallback to original
    setPhotoFile(file);
    const url = URL.createObjectURL(file);
    setPhotoPreview(url);
  }
};

