import React, { useState } from 'react';
import { useQuery } from 'react-query';
import { Card, Table, Button, Form, InputGroup, Badge, Modal } from 'react-bootstrap';
import { toast } from 'react-toastify';
import { getHousingData, deleteHousingData } from '../../services/housingService';
import { useAuth } from '../../contexts/AuthContext';
import HousingForm from './HousingForm';

const HousingData = () => {
  const { user } = useAuth();
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [showForm, setShowForm] = useState(false);
  const [selectedHousing, setSelectedHousing] = useState(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [deleteId, setDeleteId] = useState(null);

  const { data: housingData, isLoading, error, refetch } = useQuery(
    ['housingData', currentPage, searchTerm],
    () => getHousingData({ page: currentPage, search: searchTerm }),
    { keepPreviousData: false }
  );

  const handleEdit = (housing) => {
    setSelectedHousing(housing);
    setShowForm(true);
  };

  const handleDelete = (id) => {
    console.log('delete id: ',id)
    setDeleteId(id);
    setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
    try {
      await deleteHousingData(deleteId);
      toast.success('Data berhasil dihapus');
      refetch();
      setShowDeleteModal(false);
    } catch (error) {
      toast.error('Gagal menghapus data');
    }
  };

  const handleFormClose = () => {
    setShowForm(false);
    setSelectedHousing(null);
  };

  const handleFormSuccess = () => {
    refetch();
    handleFormClose();
  };

  if (isLoading) return <div className="loading-spinner">Loading...</div>;
  if (error) return <div className="error-message">Error: {error.message}</div>;

  return (
    <div className="container-fluid">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className='fw-bold'>Data Rumah</h2>
        {user?.role === 'admin' || user?.role === 'pengguna' ? (
          <Button variant="primary" onClick={() => setShowForm(true)}>
            <i className="fas fa-plus me-2"></i>
            Tambah Data
          </Button>
        ) : null}
      </div>

      <Card>
        <Card.Body>
          <div className="row mb-3">
            <div className="col-md-6">
              <InputGroup>
                <InputGroup.Text>
                  <i className="fas fa-search"></i>
                </InputGroup.Text>
                <Form.Control
                  type="text"
                  placeholder="Cari data..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </InputGroup>
            </div>
          </div>

          <Table responsive striped hover>
            <thead>
              <tr>
                <th>No</th>
                {/* <th>Id</th> */}
                <th>Nama Kepala Keluarga</th>
                <th>Alamat</th>
                <th>Desa</th>
                <th>Kecamatan</th>
                <th>Status</th>
                <th>Aksi</th>
              </tr>
            </thead>
            <tbody>
              {housingData?.data?.map((housing, index) => (
                <tr key={housing.housing_id}>
                  <td>{(currentPage - 1) * 10 + index + 1}</td>
                  {/* <td>{housing.housing_id}</td> */}
                  <td>{housing.household_head_name}</td>
                  <td>{housing.address}</td>
                  <td>{housing.sub_district_name}</td>
                  <td>{housing.district_name}</td>
                  <td>
                    <Badge bg={housing.status === 'aktif' ? 'success' : 'secondary'}>
                      {housing.status}
                    </Badge>
                  </td>
                  <td>
                    <div className='group-this-items'>

                    <Button
                      size="sm"
                      variant="info"
                      className="me-3 action-btn"
                      onClick={() => handleEdit(housing)}
                      >
                      <i className="fas fa-edit"></i>
                    </Button>
                    {(user?.role === 'admin' || user?.role === 'pengguna') && (
                      <Button
                      size="sm"
                      variant="danger"
                      className="me-3 action-btn"
                      onClick={() => handleDelete(housing.housing_id)}
                      >
                        <i className="fas fa-trash"></i>
                      </Button>
                    )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </Table>

          {/* Pagination */}
          {housingData?.pagination && (
            <div className="d-flex justify-content-between align-items-center">
              <div>
                Menampilkan {housingData.pagination.from} - {housingData.pagination.to} dari {housingData.pagination.total} data
              </div>
              <div>
                <Button
                  variant="outline-primary"
                  size="sm"
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(currentPage - 1)}
                  className="me-2"
                >
                  Sebelumnya
                </Button>
                <Button
                  variant="outline-primary"
                  size="sm"
                  disabled={currentPage >= housingData.pagination.totalPages}
                  onClick={() => setCurrentPage(currentPage + 1)}
                >
                  Selanjutnya
                </Button>
              </div>
            </div>
          )}
        </Card.Body>
      </Card>

      {/* Housing Form Modal */}
      <Modal show={showForm} onHide={handleFormClose} size="lg">
        <Modal.Header closeButton>
          <Modal.Title>
            {selectedHousing ? 'Edit Data Rumah' : 'Tambah Data Rumah'}
          </Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <HousingForm
            housing={selectedHousing}
            onSuccess={handleFormSuccess}
            onCancel={handleFormClose}
          />
        </Modal.Body>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal show={showDeleteModal} onHide={() => setShowDeleteModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Konfirmasi Hapus</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          Apakah Anda yakin ingin menghapus data ini?
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>
            Batal
          </Button>
          <Button variant="danger" onClick={confirmDelete}>
            Hapus
          </Button>
        </Modal.Footer>
      </Modal>
    </div>
  );
};

export default HousingData; 