import React, { useState } from 'react';
import { useQuery } from 'react-query';
import { Card, Row, Col, Form, Button, Table, Badge } from 'react-bootstrap';
import { Chart as ChartJS, ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title } from 'chart.js';
import { Bar, Doughnut, Pie } from 'react-chartjs-2';
import { getDashboardSummary, getDistrictStats, getAssessmentSummary } from '../../services/dashboardService';

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Reports = () => {
  const [selectedReport, setSelectedReport] = useState('summary');
  const [selectedDistrict, setSelectedDistrict] = useState('');

  const { data: summaryData, isLoading: summaryLoading } = useQuery(
    ['dashboardSummary'],
    getDashboardSummary
  );

  const { data: districtStats, isLoading: districtLoading } = useQuery(
    ['districtStats'],
    getDistrictStats
  );

  const { data: assessmentData, isLoading: assessmentLoading } = useQuery(
    ['assessmentSummary', selectedDistrict],
    () => getAssessmentSummary(selectedDistrict)
  );

  const isLoading = summaryLoading || districtLoading || assessmentLoading;

  const renderSummaryReport = () => (
    <Row>
      <Col md={6}>
        <Card className="mb-4">
          <Card.Header>
            <h5>Distribusi Jenis Kelamin</h5>
          </Card.Header>
          <Card.Body>
            {summaryData?.gender_distribution && (
              <Doughnut
                data={{
                  labels: Object.keys(summaryData.gender_distribution),
                  datasets: [{
                    data: Object.values(summaryData.gender_distribution),
                    backgroundColor: ['#007bff', '#dc3545'],
                    borderWidth: 2
                  }]
                }}
                options={{
                  responsive: true,
                  plugins: {
                    legend: {
                      position: 'bottom'
                    }
                  }
                }}
              />
            )}
          </Card.Body>
        </Card>
      </Col>

      <Col md={6}>
        <Card className="mb-4">
          <Card.Header>
            <h5>Distribusi Pendidikan</h5>
          </Card.Header>
          <Card.Body>
            {summaryData?.education_distribution && (
              <Pie
                data={{
                  labels: Object.keys(summaryData.education_distribution),
                  datasets: [{
                    data: Object.values(summaryData.education_distribution),
                    backgroundColor: [
                      '#007bff', '#28a745', '#ffc107', '#dc3545',
                      '#6f42c1', '#fd7e14', '#20c997', '#e83e8c'
                    ],
                    borderWidth: 2
                  }]
                }}
                options={{
                  responsive: true,
                  plugins: {
                    legend: {
                      position: 'bottom'
                    }
                  }
                }}
              />
            )}
          </Card.Body>
        </Card>
      </Col>

      <Col md={12}>
        <Card className="mb-4">
          <Card.Header>
            <h5>Distribusi Penghasilan</h5>
          </Card.Header>
          <Card.Body>
            {summaryData?.income_distribution && (
              <Bar
                data={{
                  labels: Object.keys(summaryData.income_distribution),
                  datasets: [{
                    label: 'Jumlah KK',
                    data: Object.values(summaryData.income_distribution),
                    backgroundColor: '#007bff',
                    borderColor: '#0056b3',
                    borderWidth: 1
                  }]
                }}
                options={{
                  responsive: true,
                  plugins: {
                    legend: {
                      display: false
                    }
                  },
                  scales: {
                    y: {
                      beginAtZero: true
                    }
                  }
                }}
              />
            )}
          </Card.Body>
        </Card>
      </Col>
    </Row>
  );

  const renderDistricalReport = () => (
    <Row>
      <Col md={12}>
        <Card className="mb-4">
          <Card.Header>
            <h5>Statistik per Kecamatan</h5>
          </Card.Header>
          <Card.Body>
            <Table responsive striped>
              <thead>
                <tr>
                  <th>Kecamatan</th>
                  <th>Total Rumah</th>
                  <th>Layak Huni</th>
                  <th>Kurang Layak Huni</th>
                  <th>Tidak Layak Huni</th>
                  <th>Rata-rata Skor</th>
                </tr>
              </thead>
              <tbody>
                {districtStats?.map((district, index) => (
                  <tr key={index}>
                    <td>{district.kecamatan}</td>
                    <td>{district.total_houses}</td>
                    <td>
                      <Badge bg="success">{district.layak_huni}</Badge>
                    </td>
                    <td>
                      <Badge bg="warning">{district.kurang_layak_huni}</Badge>
                    </td>
                    <td>
                      <Badge bg="danger">{district.tidak_layak_huni}</Badge>
                    </td>
                    <td>
                      <strong>{district.average_score?.toFixed(1) || '-'}</strong>
                    </td>
                  </tr>
                ))}
              </tbody>
            </Table>
          </Card.Body>
        </Card>
      </Col>

      <Col md={12}>
        <Card>
          <Card.Header>
            <h5>Grafik Statistik per Kecamatan</h5>
          </Card.Header>
          <Card.Body>
            {districtStats && (
              <Bar
                data={{
                  labels: districtStats.map(r => r.kecamatan),
                  datasets: [
                    {
                      label: 'Layak Huni',
                      data: districtStats.map(r => r.layak_huni),
                      backgroundColor: '#28a745'
                    },
                    {
                      label: 'Kurang Layak Huni',
                      data: districtStats.map(r => r.kurang_layak_huni),
                      backgroundColor: '#ffc107'
                    },
                    {
                      label: 'Tidak Layak Huni',
                      data: districtStats.map(r => r.tidak_layak_huni),
                      backgroundColor: '#dc3545'
                    }
                  ]
                }}
                options={{
                  responsive: true,
                  plugins: {
                    legend: {
                      position: 'top'
                    }
                  },
                  scales: {
                    x: {
                      stacked: true
                    },
                    y: {
                      stacked: true,
                      beginAtZero: true
                    }
                  }
                }}
              />
            )}
          </Card.Body>
        </Card>
      </Col>
    </Row>
  );

  const renderAssessmentReport = () => (
    <Row>
      <Col md={12}>
        <Card className="mb-4">
          <Card.Header>
            <div className="d-flex justify-content-between align-items-center">
              <h5>Laporan Penilaian Kelayakan Huni</h5>
              <Form.Select
                value={selectedDistrict}
                onChange={(e) => setSelectedDistrict(e.target.value)}
                style={{ width: '200px' }}
              >
                <option value="">Semua Kecamatan</option>
                <option value="BEO">BEO</option>
                <option value="BEO UTARA">BEO UTARA</option>
                <option value="RAINIS">RAINIS</option>
                <option value="ESSANG">ESSANG</option>
                <option value="ESSANG SELATAN">ESSANG SELATAN</option>
                <option value="GEMEH">GEMEH</option>
                <option value="NANUSA">NANUSA</option>
                <option value="MIANGAS">MIANGAS</option>
                <option value="LIRUNG">LIRUNG</option>
                <option value="SALIBABU">SALIBABU</option>
                <option value="KALONGAN">KALONGAN</option>
                <option value="MELONGUANE">MELONGUANE</option>
                <option value="MELONGUANE TIMUR">MELONGUANE TIMUR</option>
                <option value="MELONGUANE BARAT">MELONGUANE BARAT</option>
              </Form.Select>
            </div>
          </Card.Header>
          <Card.Body>
            {assessmentData && (
              <div>
                <Row>
                  <Col md={3}>
                    <div className="text-center">
                      <h3 className="text-success">{assessmentData.total_assessed}</h3>
                      <p>Total Dinilai</p>
                    </div>
                  </Col>
                  <Col md={3}>
                    <div className="text-center">
                      <h3 className="text-success">{assessmentData.layak_huni}</h3>
                      <p>Layak Huni</p>
                    </div>
                  </Col>
                  <Col md={3}>
                    <div className="text-center">
                      <h3 className="text-warning">{assessmentData.kurang_layak_huni}</h3>
                      <p>Kurang Layak Huni</p>
                    </div>
                  </Col>
                  <Col md={3}>
                    <div className="text-center">
                      <h3 className="text-danger">{assessmentData.tidak_layak_huni}</h3>
                      <p>Tidak Layak Huni</p>
                    </div>
                  </Col>
                </Row>

                <Row className="mt-4">
                  <Col md={6}>
                    <h6>Distribusi Skor Kelayakan</h6>
                    <Doughnut
                      data={{
                        labels: ['Layak Huni', 'Kurang Layak Huni', 'Tidak Layak Huni'],
                        datasets: [{
                          data: [
                            assessmentData.layak_huni,
                            assessmentData.kurang_layak_huni,
                            assessmentData.tidak_layak_huni
                          ],
                          backgroundColor: ['#28a745', '#ffc107', '#dc3545'],
                          borderWidth: 2
                        }]
                      }}
                      options={{
                        responsive: true,
                        plugins: {
                          legend: {
                            position: 'bottom'
                          }
                        }
                      }}
                    />
                  </Col>
                  <Col md={6}>
                    <h6>Rata-rata Skor per Kecamatan</h6>
                    {assessmentData.average_scores && (
                      <Bar
                        data={{
                          labels: assessmentData.average_scores.map(item => item.kecamatan),
                          datasets: [{
                            label: 'Rata-rata Skor',
                            data: assessmentData.average_scores.map(item => item.average_score),
                            backgroundColor: '#007bff',
                            borderColor: '#0056b3',
                            borderWidth: 1
                          }]
                        }}
                        options={{
                          responsive: true,
                          plugins: {
                            legend: {
                              display: false
                            }
                          },
                          scales: {
                            y: {
                              beginAtZero: true,
                              max: 100
                            }
                          }
                        }}
                      />
                    )}
                  </Col>
                </Row>
              </div>
            )}
          </Card.Body>
        </Card>
      </Col>
    </Row>
  );

  const renderReportContent = () => {
    switch (selectedReport) {
      case 'summary':
        return renderSummaryReport();
      case 'districal':
        return renderDistricalReport();
      case 'assessment':
        return renderAssessmentReport();
      default:
        return renderSummaryReport();
    }
  };

  if (isLoading) return <div className="loading-spinner">Loading laporan...</div>;

  return (
    <div className="container-fluid">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2>Laporan dan Statistik</h2>
        <div className="d-flex gap-2">
          <Button 
            variant="outline-primary" 
            size="sm"
            onClick={() => window.print()}
          >
            <i className="fas fa-print me-2"></i>
            Cetak Laporan
          </Button>
        </div>
      </div>

      <Card className="mb-4">
        <Card.Body>
          <div className="d-flex gap-3">
            <Button
              variant={selectedReport === 'summary' ? 'primary' : 'outline-primary'}
              onClick={() => setSelectedReport('summary')}
            >
              Ringkasan Umum
            </Button>
            <Button
              variant={selectedReport === 'districal' ? 'primary' : 'outline-primary'}
              onClick={() => setSelectedReport('districal')}
            >
              Laporan Districal
            </Button>
            <Button
              variant={selectedReport === 'assessment' ? 'primary' : 'outline-primary'}
              onClick={() => setSelectedReport('assessment')}
            >
              Laporan Penilaian
            </Button>
          </div>
        </Card.Body>
      </Card>

      {renderReportContent()}
    </div>
  );
};

export default Reports; 